import base64

# target: the end of Global Active Indicator
t1_b64 = "ICAgICAgICAgICAgPC9kaXY+CiAgICAgICAgICA8L2Rpdj4KICAgICAgICBpfQ=="
r1_b64 = ""

# Quick fix for wait refresh => await refresh()
r4_b64 = ""

t1 = base64.b64decode(t1_b64).decode('utf-8')
r1 = base64.b64decode(r1_b64).decode('utf-8')
r4 = base64.b64decode(r4_b64).decode('utf-8')

# We need to replace the t4 again with r4 to fix mait refresh()
t4_b64 = ""
t4 = base64.b64decode(t4_b64).decode('utf-8')

with open('src/pages/ProviderSettings.tsx', 'r', encoding='utf-8') as f:
    text = f.read()

# Replace translation string correctly 
r1 = r1.replace("'useTranslation().t('providers.save')'", "t('providers.save')")
r1 = r1.replace("'useTranslation().t('providers.edit')'", "t('providers.edit')")
r1 = r1.replace("is1Selected", "isSelected")

t1 = t1.replace('\r\n', '\n')
r1 = r1.replace('\r\n', '\n')
t4 = t4.replace('\r\n', '\n')
r4 = r4.replace('\r\n', '\n')
text = text.replace('\r\n', '\n')

text = text.replace(t1, r1)
text = text.replace(t4, r4)

with open('src/pages/ProviderSettings.tsx', 'w', encoding='utf-8') as f:
    f.write(text)

print("Patched UI successfully")
